// pp:data-source local
func newNovelClientReportCmd(flags *rootFlags) *cobra.Command {
	var flagLocalDays int
	var flagOffsiteDays int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "client-report [client]",
		Short: "One QBR-ready health report for a single client: devices, agents, screenshot pass rate, stale backups, and open alerts",
		Long: strings.Trim(`
Use this command for ONE named client's full QBR-ready health report.
Do NOT use it to rank all clients by risk; use 'client-risk' instead.

Bundles the client's appliances (with last-seen, storage pressure, and open
alert counts) and protected agents (with screenshot-verification status and
backup recency) from the local store into a single JSON document. Client
matching is case-insensitive on clientCompanyName.`, "\n"),
		Example: strings.Trim(`
  # Full health bundle for one client, ready to drop into a QBR deck
  datto-bcdr-cli client-report "Acme Corp" --json

  # Tighter staleness thresholds for a client with aggressive RPO targets
  datto-bcdr-cli client-report "Acme Corp" --local-days 1 --offsite-days 2 --json`, "\n"),
		Annotations: map[string]string{
			"mcp:read-only": "true",
			"pp:happy-args": "<client>=Acme Corp",
		},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would build a single-client health report from the local store")
				return nil
			}
			if len(args) < 1 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("<client> is required"))
			}
			if err := validateDataSourceStrategy(flags, "local"); err != nil {
				return err
			}
			client := args[0]
			if dbPath == "" {
				dbPath = defaultDBPath("datto-bcdr-cli")
			}
			db, err := nvOpenStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer db.Close()

			if !hintIfUnsynced(cmd, db, "") {
				hintIfStale(cmd, db, "", flags.maxAge)
			}

			now := time.Now()
			nowEpoch := now.Unix()
			report := clientReport{
				Client:  client,
				Devices: make([]clientReportDevice, 0),
				Agents:  make([]clientReportAgent, 0),
			}

			// Devices for the client (case-insensitive match on clientCompanyName).
			// Storage fields tolerate both the nested {size: N} object shape and a
			// bare scalar; real payload shape pending live-tenant confirmation.
			devRows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.serialNumber'), ''),
					COALESCE(json_extract(data,'$.name'), ''),
					COALESCE(json_extract(data,'$.model'), ''),
					json_extract(data,'$.lastSeenDate'),
					COALESCE(json_extract(data,'$.localStorageUsed.size'), json_extract(data,'$.localStorageUsed')),
					COALESCE(json_extract(data,'$.localStorageAvailable.size'), json_extract(data,'$.localStorageAvailable')),
					json_extract(data,'$.alertCount')
				FROM "device"
				WHERE LOWER(COALESCE(json_extract(data,'$.clientCompanyName'), '')) = LOWER(?)`, client)
			if err != nil {
				return fmt.Errorf("querying devices: %w", err)
			}
			defer devRows.Close()
			serials := map[string]bool{}
			for devRows.Next() {
				var (
					serial, name, model string
					lastSeen            sql.NullString
					localUsed           sql.NullFloat64
					localAvail          sql.NullFloat64
					alertCount          sql.NullInt64
				)
				if err := devRows.Scan(&serial, &name, &model, &lastSeen, &localUsed, &localAvail, &alertCount); err != nil {
					return fmt.Errorf("scanning device: %w", err)
				}
				if serial != "" {
					serials[serial] = true
				}

				offline := true
				lastSeenStr := "never"
				if lastSeen.Valid {
					lastSeenStr = lastSeen.String
					if t, ok := parseFlexibleTime(lastSeen.String); ok {
						offline = now.Sub(t) > 24*time.Hour
					}
				}
				used := localUsed.Float64
				denom := used + localAvail.Float64
				pct := 0.0
				if denom > 0 {
					pct = used / denom * 100
				}
				alerts := 0
				if alertCount.Valid {
					alerts = int(alertCount.Int64)
				}
				report.OpenAlerts += alerts
				report.Devices = append(report.Devices, clientReportDevice{
					SerialNumber: serial,
					Name:         name,
					Model:        model,
					LastSeen:     lastSeenStr,
					Offline:      offline,
					LocalUsedPct: pct,
					AlertCount:   alerts,
				})
			}
			if err := devRows.Err(); err != nil {
				return fmt.Errorf("iterating devices: %w", err)
			}
			devRows.Close()

			// Agents for the client: matched by clientCompanyName, with a
			// device-serial fallback so agents lacking the client field still
			// land in the report when their appliance belongs to the client.
			agRows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.agentName'), ''),
					COALESCE(json_extract(data,'$.deviceSerialNumber'), ''),
					COALESCE(json_extract(data,'$.clientCompanyName'), ''),
					json_extract(data,'$.lastScreenshotAttemptStatus'),
					json_extract(data,'$.lastSnapshot'),
					json_extract(data,'$.latestOffsite'),
					json_extract(data,'$.isPaused'),
					json_extract(data,'$.isArchived')
				FROM "agent"`)
			if err != nil {
				return fmt.Errorf("querying agents: %w", err)
			}
			defer agRows.Close()

			localCutoff := nowEpoch - int64(flagLocalDays)*86400
			offsiteCutoff := nowEpoch - int64(flagOffsiteDays)*86400
			passed := 0
			for agRows.Next() {
				var (
					name, serial, agClient string
					screenshotOK           sql.NullBool
					lastSnapshot           sql.NullInt64
					latestOffsite          sql.NullInt64
					isPaused, isArchived   sql.NullBool
				)
				if err := agRows.Scan(&name, &serial, &agClient, &screenshotOK, &lastSnapshot, &latestOffsite, &isPaused, &isArchived); err != nil {
					return fmt.Errorf("scanning agent: %w", err)
				}
				if !strings.EqualFold(agClient, client) && !serials[serial] {
					continue
				}

				snap := int64(0)
				if lastSnapshot.Valid {
					snap = lastSnapshot.Int64
				}
				off := int64(0)
				if latestOffsite.Valid {
					off = latestOffsite.Int64
				}
				shotOK := screenshotOK.Valid && screenshotOK.Bool
				staleLocal := snap < localCutoff
				staleOffsite := off < offsiteCutoff

				if shotOK {
					passed++
				}
				if staleLocal || staleOffsite {
					report.StaleAgents++
				}
				report.Agents = append(report.Agents, clientReportAgent{
					AgentName:          name,
					DeviceSerialNumber: serial,
					ScreenshotPassed:   shotOK,
					LastSnapshotAge:    ageDays(nowEpoch, snap),
					StaleLocal:         staleLocal,
					StaleOffsite:       staleOffsite,
					Paused:             isPaused.Valid && isPaused.Bool,
					Archived:           isArchived.Valid && isArchived.Bool,
				})
			}
			if err := agRows.Err(); err != nil {
				return fmt.Errorf("iterating agents: %w", err)
			}

			report.TotalAgents = len(report.Agents)
			if report.TotalAgents > 0 {
				report.ScreenshotPassPct = float64(passed) / float64(report.TotalAgents) * 100
			}
			if len(report.Devices) == 0 && report.TotalAgents == 0 {
				report.Note = fmt.Sprintf("no synced devices or agents matched client %q; run 'datto-bcdr-cli sync' first or check the client name with 'datto-bcdr-cli client-risk'", client)
			}

			// Deterministic ordering for stable diffs and tests.
			sort.SliceStable(report.Devices, func(i, j int) bool {
				return report.Devices[i].SerialNumber < report.Devices[j].SerialNumber
			})
			sort.SliceStable(report.Agents, func(i, j int) bool {
				return report.Agents[i].AgentName < report.Agents[j].AgentName
			})

			return flags.printJSON(cmd, report)
		},
	}
	cmd.Flags().IntVar(&flagLocalDays, "local-days", 1, "Count an agent stale when its last local snapshot is older than N days")
	cmd.Flags().IntVar(&flagOffsiteDays, "offsite-days", 3, "Count an agent stale when its last offsite sync is older than N days")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (defaults to standard location)")
	return cmd
}
